/**
 * create-missing-sanity-events.js
 * Creates Sanity documents for events missing from Sanity.
 * Uses createIfNotExists — will NOT overwrite existing docs or their uploadedImages.
 * Reads missing slugs from /tmp/missing-slugs.json (generated by gap analysis).
 */

const { createClient } = require('@sanity/client');
const fs = require('fs');
const path = require('path');

const client = createClient({
  projectId: 't5nsm79o',
  dataset: 'production',
  apiVersion: '2026-03-20',
  token: process.env.SANITY_WRITE_TOKEN,
  useCdn: false,
});

async function run() {
  const missingSlugs = new Set(JSON.parse(fs.readFileSync('/tmp/missing-slugs.json', 'utf8')));
  const events = JSON.parse(fs.readFileSync(path.join(__dirname, '../events-data.json'), 'utf8'));
  const toCreate = events.filter(e => missingSlugs.has(e.slug));

  console.log(`Creating ${toCreate.length} missing Sanity event documents...`);
  let created = 0, errors = 0;

  for (const event of toCreate) {
    const doc = {
      _type: 'event',
      _id: `event-${event.slug}`,
      slug: { _type: 'slug', current: event.slug },
      title: event.title || '',
      vnTitle: event.vnTitle || undefined,
      dateISO: event.dateISO || event.sortDate || undefined,
      endDateISO: event.endDateISO || undefined,
      displayDate: event.displayDate || '',
      category: event.category || '',
      location: event.location || '',
      description: event.description || '',
      vnDescription: event.vnDescription || '',
      legacyImageUrls: (event.images || []).filter(Boolean),
      uploadedImages: [],
      videoUrl: event.videoUrl || undefined,
      bandcampAlbumId: event.bandcampAlbumId || undefined,
      isBioPage: event.isBioPage || false,
      wpLink: event.wpLink || undefined,
      sortDate: event.sortDate || event.dateISO || undefined,
    };

    // Strip undefined values
    Object.keys(doc).forEach(k => doc[k] === undefined && delete doc[k]);

    try {
      await client.createIfNotExists(doc);
      console.log(`  ✓ ${event.slug}`);
      created++;
    } catch (err) {
      console.log(`  ✗ ${event.slug}: ${err.message}`);
      errors++;
    }
  }

  console.log(`\nDone. Created: ${created}, Errors: ${errors}`);
}

run().catch(console.error);
